async (response, ctx) => {
  const { TaskScheduler } = require('../src/agent/scheduler');
  // Override agent.runBrowserAction to succeed (default eval agent has no active view).
  const orig = ctx.agent.runBrowserAction.bind(ctx.agent);
  ctx.agent.runBrowserAction = async () => ({ ok: true, navigated: true });
  const s = new TaskScheduler(ctx.agent);
  await s.load();
  const task = s.list().find(t => t.id === 'morning-check');
  if (!task) return [{ok: false, message: 'task not loaded from disk'}];
  const r = await s._runOne(task, new Date());
  ctx.agent.runBrowserAction = orig;
  return [
    {ok: r.ok === true, message: 'manual run wrapper ok'},
    {ok: s.list()[0].lastRun !== null, message: 'lastRun updated'},
    {ok: s.list()[0].lastResult.ok === true, message: 'lastResult.ok reflects successful action'}
  ];
}
